solve(Nums) ->
    SumA = sum_primes_indices(Nums, 0, 0),
    SumB = lists:sum(Nums) - SumA,
    abs(SumA - SumB).

sum_primes_indices([], _, Sum) -> Sum;
sum_primes_indices([H | T], Index, Sum) ->
    case is_prime(Index) of
        true -> sum_primes_indices(T, Index + 1, Sum + H);
        false -> sum_primes_indices(T, Index + 1, Sum)
    end.

